import numpy as np
import cv2
from PIL import Image
from typing import List, Tuple, Optional
import torch
from basicsr.archs.rrdbnet_arch import RRDBNet
from realesrgan import RealESRGANer
import warnings
warnings.filterwarnings('ignore')


class Upscaler:
    """Handles image upscaling with multiple methods"""

    def __init__(self, method: str = "realesrgan"):
        self.method = method
        self.model = None
        self.device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')

        if method == "realesrgan":
            self._init_realesrgan()

    def _init_realesrgan(self):
        """Initialize Real-ESRGAN model"""
        try:
            # Use RealESRGAN x4plus model for high quality
            model = RRDBNet(num_in_ch=3, num_out_ch=3, num_feat=64, num_block=23, num_grow_ch=32, scale=4)
            model_path = 'https://github.com/xinntao/Real-ESRGAN/releases/download/v0.1.0/RealESRGAN_x4plus.pth'

            self.model = RealESRGANer(
                scale=4,
                model_path=model_path,
                model=model,
                tile=0,
                tile_pad=10,
                pre_pad=0,
                half=False,
                device=self.device
            )
        except Exception as e:
            print(f"Failed to load Real-ESRGAN, falling back to CV2: {e}")
            self.method = "cv2"

    def upscale(self, image: np.ndarray, scale: float) -> np.ndarray:
        """Upscale image by given factor"""
        if scale == 1.0:
            return image

        if self.method == "realesrgan" and self.model and scale in [2.0, 4.0]:
            try:
                # Real-ESRGAN works best with 4x, so for 2x we upscale 4x then downscale
                if scale == 2.0:
                    upscaled, _ = self.model.enhance(image, outscale=4)
                    h, w = image.shape[:2]
                    upscaled = cv2.resize(upscaled, (w * 2, h * 2), interpolation=cv2.INTER_LANCZOS4)
                else:  # scale == 4.0
                    upscaled, _ = self.model.enhance(image, outscale=4)
                return upscaled
            except Exception as e:
                print(f"Real-ESRGAN failed, using CV2: {e}")
                return self._cv2_upscale(image, scale)
        else:
            return self._cv2_upscale(image, scale)

    def _cv2_upscale(self, image: np.ndarray, scale: float) -> np.ndarray:
        """Fallback upscaling using OpenCV"""
        h, w = image.shape[:2]
        new_h, new_w = int(h * scale), int(w * scale)

        if scale > 1.0:
            # Use Lanczos for upscaling
            return cv2.resize(image, (new_w, new_h), interpolation=cv2.INTER_LANCZOS4)
        else:
            # Use Area for downscaling
            return cv2.resize(image, (new_w, new_h), interpolation=cv2.INTER_AREA)


class MultiScaleProcessor:
    """Process images at multiple scales"""

    def __init__(self, upscaler: Optional[Upscaler] = None):
        self.upscaler = upscaler or Upscaler()

    def generate_scales(self, image: np.ndarray, scales: List[float]) -> List[np.ndarray]:
        """Generate image at multiple scales"""
        scaled_images = []

        for scale in scales:
            if scale >= 1.0:
                # Upscale
                scaled = self.upscaler.upscale(image, scale)
            else:
                # Downscale
                scaled = self.upscaler._cv2_upscale(image, scale)

            scaled_images.append(scaled)

        return scaled_images

    def resize_to_common(self, images: List[np.ndarray], target_size: Tuple[int, int]) -> List[np.ndarray]:
        """Resize all images to common size for blending"""
        resized = []

        for img in images:
            if img.shape[:2] != target_size[::-1]:  # OpenCV uses (width, height)
                resized_img = cv2.resize(img, target_size, interpolation=cv2.INTER_LINEAR)
                resized.append(resized_img)
            else:
                resized.append(img)

        return resized

