import numpy as np
import cv2
from typing import Tuple, List, Optional
from PIL import Image


class ImageProcessor:
    """Utility functions for image processing"""

    @staticmethod
    def normalize_size(image: np.ndarray, max_dimension: int = 1024) -> np.ndarray:
        """Normalize image size for processing"""
        h, w = image.shape[:2]

        if max(h, w) > max_dimension:
            scale = max_dimension / max(h, w)
            new_h, new_w = int(h * scale), int(w * scale)
            return cv2.resize(image, (new_w, new_h), interpolation=cv2.INTER_AREA)

        return image

    @staticmethod
    def calculate_sharpness(image: np.ndarray) -> float:
        """Calculate image sharpness using Laplacian variance"""
        if len(image.shape) == 3:
            gray = cv2.cvtColor(image, cv2.COLOR_RGB2GRAY)
        else:
            gray = image

        laplacian = cv2.Laplacian(gray, cv2.CV_64F)
        return laplacian.var()

    @staticmethod
    def detect_edges(image: np.ndarray, 
                    low_threshold: int = 50, 
                    high_threshold: int = 150) -> np.ndarray:
        """Detect edges using Canny edge detector"""
        if len(image.shape) == 3:
            gray = cv2.cvtColor(image, cv2.COLOR_RGB2GRAY)
        else:
            gray = image

        edges = cv2.Canny(gray, low_threshold, high_threshold)
        return edges

    @staticmethod
    def create_difference_map(img1: np.ndarray, img2: np.ndarray) -> np.ndarray:
        """Create a difference map between two images"""
        # Ensure same size
        if img1.shape != img2.shape:
            img2 = cv2.resize(img2, (img1.shape[1], img1.shape[0]))

        # Calculate absolute difference
        diff = cv2.absdiff(img1.astype(np.float32), img2.astype(np.float32))

        # Normalize to 0-255
        diff_normalized = (diff / diff.max() * 255).astype(np.uint8) if diff.max() > 0 else diff.astype(np.uint8)

        # Convert to heatmap
        if len(diff_normalized.shape) == 3:
            diff_gray = cv2.cvtColor(diff_normalized, cv2.COLOR_RGB2GRAY)
        else:
            diff_gray = diff_normalized

        heatmap = cv2.applyColorMap(diff_gray, cv2.COLORMAP_JET)

        return heatmap

    @staticmethod
    def enhance_details(image: np.ndarray, amount: float = 1.0) -> np.ndarray:
        """Enhance image details using unsharp masking"""
        # Create blurred version
        blurred = cv2.GaussianBlur(image, (0, 0), 2.0)

        # Calculate the sharpened image
        sharpened = cv2.addWeighted(image, 1.0 + amount, blurred, -amount, 0)

        return np.clip(sharpened, 0, 255).astype(np.uint8)

    @staticmethod
    def adjust_contrast(image: np.ndarray, factor: float = 1.0) -> np.ndarray:
        """Adjust image contrast"""
        # Convert to float
        img_float = image.astype(np.float32)

        # Calculate mean
        mean = np.mean(img_float)

        # Adjust contrast
        adjusted = mean + factor * (img_float - mean)

        return np.clip(adjusted, 0, 255).astype(np.uint8)


class FrequencyAnalyzer:
    """Analyze frequency content of images"""

    @staticmethod
    def get_frequency_spectrum(image: np.ndarray) -> np.ndarray:
        """Get frequency spectrum of image"""
        if len(image.shape) == 3:
            gray = cv2.cvtColor(image, cv2.COLOR_RGB2GRAY)
        else:
            gray = image

        # Compute FFT
        f_transform = np.fft.fft2(gray)
        f_shift = np.fft.fftshift(f_transform)

        # Get magnitude spectrum
        magnitude = np.abs(f_shift)
        magnitude_spectrum = 20 * np.log(magnitude + 1)

        return magnitude_spectrum

    @staticmethod
    def separate_frequencies(image: np.ndarray, 
                           cutoff_ratio: float = 0.1) -> Tuple[np.ndarray, np.ndarray]:
        """Separate image into low and high frequency components"""
        if len(image.shape) == 3:
            # Process each channel separately
            channels = []
            for c in range(3):
                low, high = FrequencyAnalyzer._separate_channel(image[:,:,c], cutoff_ratio)
                channels.append((low, high))

            low_freq = np.stack([ch[0] for ch in channels], axis=2)
            high_freq = np.stack([ch[1] for ch in channels], axis=2)

            return low_freq, high_freq
        else:
            return FrequencyAnalyzer._separate_channel(image, cutoff_ratio)

    @staticmethod
    def _separate_channel(channel: np.ndarray, cutoff_ratio: float) -> Tuple[np.ndarray, np.ndarray]:
        """Separate single channel into frequency components"""
        # FFT
        f_transform = np.fft.fft2(channel)
        f_shift = np.fft.fftshift(f_transform)

        # Create masks
        rows, cols = channel.shape
        crow, ccol = rows // 2, cols // 2

        # Low-pass mask
        mask_low = np.zeros((rows, cols), dtype=np.float32)
        r = int(min(rows, cols) * cutoff_ratio)
        cv2.circle(mask_low, (ccol, crow), r, 1, -1)

        # High-pass mask
        mask_high = 1 - mask_low

        # Apply masks
        f_low = f_shift * mask_low
        f_high = f_shift * mask_high

        # Inverse FFT
        low_ishift = np.fft.ifftshift(f_low)
        low_freq = np.fft.ifft2(low_ishift)
        low_freq = np.real(low_freq)

        high_ishift = np.fft.ifftshift(f_high)
        high_freq = np.fft.ifft2(high_ishift)
        high_freq = np.real(high_freq)

        return (np.clip(low_freq, 0, 255).astype(np.uint8),
                np.clip(high_freq + 127, 0, 255).astype(np.uint8))

