                    threshold = st.slider("Quality threshold", 0.3, 0.9, 0.7)
                    weighting_scheme = PerceptualScheme(quality_threshold=threshold)

            # Scale configuration
            st.subheader("📏 Scale Configuration")
            scales = []

            col1, col2 = st.columns(2)
            with col1:
                if st.checkbox("0.25x", value=True):
                    scales.append(0.25)
                if st.checkbox("0.5x", value=True):
                    scales.append(0.5)
                if st.checkbox("0.75x", value=True):
                    scales.append(0.75)
            with col2:
                if st.checkbox("1x (Original)", value=True):
                    scales.append(1.0)
                if st.checkbox("2x", value=True):
                    scales.append(2.0)
                if st.checkbox("4x", value=True):
                    scales.append(4.0)

            st.session_state.scales = sorted(scales)

            # Advanced options
            with st.expander("🔧 Advanced Options"):
                show_intermediate = st.checkbox("Show intermediate scales", value=False)
                show_weights = st.checkbox("Show weight visualization", value=True)
                edge_overlay = st.checkbox("Edge detection overlay", value=False)
                live_preview = st.checkbox("Live preview", value=True)

            # Process button
            if st.button("🚀 Process Image", type="primary", use_container_width=True):
                with st.spinner("Processing..."):
                    progress_bar = st.progress(0, "Starting...")

                    # Process scales
                    st.session_state.processed_images = process_scales(
