                    output.getvalue(),
                    "blended_result.png",
                    "image/png"
                )

            with col2:
                # Export settings
                settings = {
                    'scales': st.session_state.scales,
                    'weights': st.session_state.weights.tolist() if st.session_state.weights is not None else None,
                    'scheme': scheme_type if not use_composite else 'composite'
                }
                st.download_button(
                    "Download Settings",
                    json.dumps(settings, indent=2),
                    "blend_settings.json",
                    "application/json"
                )


if __name__ == "__main__":
    main()

