class Upscaler:
    """Handles image upscaling with OpenCV methods"""

    def __init__(self, method: str = "cv2"):
        self.method = method

    def upscale(self, image: np.ndarray, scale: float) -> np.ndarray:
        """Upscale image by given factor"""
        if scale == 1.0:
            return image

        return self._cv2_upscale(image, scale)

    def _cv2_upscale(self, image: np.ndarray, scale: float) -> np.ndarray:
        """Upscaling using OpenCV with high-quality interpolation"""
        h, w = image.shape[:2]
        new_h, new_w = int(h * scale), int(w * scale)

        if scale > 1.0:
            # Use Lanczos for upscaling - high quality
            result = cv2.resize(image, (new_w, new_h), interpolation=cv2.INTER_LANCZOS4)

            # Optional: Apply slight sharpening for upscaled images
            if scale >= 2.0:
                kernel = np.array([[-1,-1,-1],
                                 [-1, 9,-1],
                                 [-1,-1,-1]]) / 9.0
                result = cv2.filter2D(result, -1, kernel)
                result = np.clip(result, 0, 255).astype(np.uint8)
        else:
            # Use Area for downscaling - prevents aliasing
            result = cv2.resize(image, (new_w, new_h), interpolation=cv2.INTER_AREA)

        return result


class MultiScaleProcessor:
    """Process images at multiple scales"""

    def __init__(self, upscaler: Optional[Upscaler] = None):
        self.upscaler = upscaler or Upscaler()

    def generate_scales(self, image: np.ndarray, scales: List[float]) -> List[np.ndarray]:
        """Generate image at multiple scales"""
        scaled_images = []

        for scale in scales:
            scaled = self.upscaler.upscale(image, scale)
            scaled_images.append(scaled)

        return scaled_images

    def resize_to_common(self, images: List[np.ndarray], target_size: Tuple[int, int]) -> List[np.ndarray]:
        """Resize all images to common size for blending"""
        resized = []

        for img in images:
            if img.shape[:2] != target_size[::-1]:  # OpenCV uses (width, height)
                resized_img = cv2.resize(img, target_size, interpolation=cv2.INTER_LINEAR)
                resized.append(resized_img)
            else:
                resized.append(img)

        return resized

