import numpy as np
from abc import ABC, abstractmethod
from typing import List, Dict, Tuple
import cv2
from scipy.ndimage import gaussian_filter


class WeightingScheme(ABC):
    """Base class for all weighting schemes"""

    @abstractmethod
    def calculate_weights(self, scales: List[float], image_data: Dict = None) -> np.ndarray:
        """Calculate weights for given scales"""
        pass

    def normalize_weights(self, weights: np.ndarray) -> np.ndarray:
        """Normalize weights to sum to 1"""
        total = np.sum(weights)
        if total > 0:
            return weights / total
        return weights


class ExponentialDecayScheme(WeightingScheme):
    """Exponential decay weighting scheme"""

    def __init__(self, alpha: float = 1.5, beta: float = 0.5):
        self.alpha = alpha
        self.beta = beta

    def calculate_weights(self, scales: List[float], image_data: Dict = None) -> np.ndarray:
        scales_array = np.array(scales)
        weights = (scales_array ** self.alpha) * np.exp(-self.beta / scales_array)
        return self.normalize_weights(weights)


class PowerLawScheme(WeightingScheme):
    """Power law weighting scheme"""

    def __init__(self, power: float = 2.0):
        self.power = power

    def calculate_weights(self, scales: List[float], image_data: Dict = None) -> np.ndarray:
        scales_array = np.array(scales)
        weights = scales_array ** self.power
        return self.normalize_weights(weights)


class GaussianScheme(WeightingScheme):
    """Gaussian weighting centered at a specific scale"""

    def __init__(self, center: float = 1.5, sigma: float = 0.8):
        self.center = center
        self.sigma = sigma

    def calculate_weights(self, scales: List[float], image_data: Dict = None) -> np.ndarray:
        scales_array = np.array(scales)
        weights = np.exp(-((scales_array - self.center) ** 2) / (2 * self.sigma ** 2))
        return self.normalize_weights(weights)


class EdgeAdaptiveScheme(WeightingScheme):
    """Weighting based on edge density at each scale"""

    def __init__(self, edge_threshold: float = 0.1, boost_factor: float = 2.0):
        self.edge_threshold = edge_threshold
        self.boost_factor = boost_factor

    def calculate_weights(self, scales: List[float], image_data: Dict = None) -> np.ndarray:
        if image_data is None or 'images' not in image_data:
            # Fallback to exponential if no image data
            return ExponentialDecayScheme().calculate_weights(scales)

        weights = []
        for scale, img in zip(scales, image_data['images']):
            # Convert to grayscale if needed
            if len(img.shape) == 3:
                gray = cv2.cvtColor(img, cv2.COLOR_RGB2GRAY)
            else:
                gray = img

            # Calculate edge density
            edges = cv2.Canny(gray, 50, 150)
            edge_density = np.mean(edges > 0)

            # Base weight from scale
            base_weight = scale ** 1.5

            # Boost based on edge density
            if edge_density > self.edge_threshold:
                weight = base_weight * (1 + self.boost_factor * edge_density)
            else:
                weight = base_weight

            weights.append(weight)

        return self.normalize_weights(np.array(weights))


class FrequencyBasedScheme(WeightingScheme):
    """Weighting based on frequency content"""

    def __init__(self, high_freq_boost: float = 2.0):
        self.high_freq_boost = high_freq_boost

    def calculate_weights(self, scales: List[float], image_data: Dict = None) -> np.ndarray:
        if image_data is None or 'images' not in image_data:
            return ExponentialDecayScheme().calculate_weights(scales)

        weights = []
        for scale, img in zip(scales, image_data['images']):
            # Convert to grayscale
            if len(img.shape) == 3:
                gray = cv2.cvtColor(img, cv2.COLOR_RGB2GRAY)
            else:
                gray = img

            # Calculate frequency content
            f_transform = np.fft.fft2(gray)
            f_shift = np.fft.fftshift(f_transform)
            magnitude = np.abs(f_shift)

            # Calculate high frequency ratio
            h, w = magnitude.shape
            center_h, center_w = h // 2, w // 2
            radius = min(h, w) // 4

            # Create masks
            y, x = np.ogrid[:h, :w]
            high_freq_mask = ((x - center_w) ** 2 + (y - center_h) ** 2) > radius ** 2

            high_freq_energy = np.sum(magnitude[high_freq_mask])
            total_energy = np.sum(magnitude)

            high_freq_ratio = high_freq_energy / (total_energy + 1e-8)

            # Weight based on scale and frequency content
            base_weight = scale ** 1.5
            weight = base_weight * (1 + self.high_freq_boost * high_freq_ratio)

            weights.append(weight)

        return self.normalize_weights(np.array(weights))


class PerceptualScheme(WeightingScheme):
    """Weighting based on perceptual quality metrics"""

    def __init__(self, quality_threshold: float = 0.7):
        self.quality_threshold = quality_threshold

    def calculate_weights(self, scales: List[float], image_data: Dict = None) -> np.ndarray:
        # Simplified version - in practice would use SSIM/LPIPS
        if image_data is None or 'images' not in image_data:
            return ExponentialDecayScheme().calculate_weights(scales)

        weights = []
        reference = image_data.get('reference', image_data['images'][0])

        for scale, img in zip(scales, image_data['images']):
            # Simple quality metric based on sharpness
            if len(img.shape) == 3:
                gray = cv2.cvtColor(img, cv2.COLOR_RGB2GRAY)
            else:
                gray = img

            # Laplacian variance as sharpness measure
            laplacian = cv2.Laplacian(gray, cv2.CV_64F)
            sharpness = laplacian.var()

            # Normalize sharpness
            max_sharpness = 1000  # Empirical value
            quality = min(sharpness / max_sharpness, 1.0)

            # Weight based on scale and quality
            base_weight = scale ** 1.5
            if quality > self.quality_threshold:
                weight = base_weight * (1 + quality)
            else:
                weight = base_weight * quality

            weights.append(weight)

        return self.normalize_weights(np.array(weights))


class CompositeScheme(WeightingScheme):
    """Combine multiple weighting schemes"""

    def __init__(self, schemes_and_weights: List[Tuple[WeightingScheme, float]]):
        self.schemes_and_weights = schemes_and_weights
        # Normalize mixing weights
        total_weight = sum(w for _, w in schemes_and_weights)
        self.schemes_and_weights = [(s, w/total_weight) for s, w in schemes_and_weights]

    def calculate_weights(self, scales: List[float], image_data: Dict = None) -> np.ndarray:
        combined_weights = np.zeros(len(scales))

        for scheme, mix_weight in self.schemes_and_weights:
            scheme_weights = scheme.calculate_weights(scales, image_data)
            combined_weights += scheme_weights * mix_weight

        return self.normalize_weights(combined_weights)

