        result = images[0].astype(np.float32)

        for i in range(1, len(images)):
            img = images[i].astype(np.float32)
            weight = weights[i]

            # Soft light formula
            img_norm = img / 255.0
            result_norm = result / 255.0

            soft = (1 - 2 * img_norm) * result_norm * result_norm + 2 * img_norm * result_norm
            soft = soft * 255

            result = result * (1 - weight) + soft * weight

        return np.clip(result, 0, 255).astype(np.uint8)

    @staticmethod
    def hard_light(images: List[np.ndarray], weights: np.ndarray) -> np.ndarray:
        """Hard light blend mode - strong contrast"""
        result = images[0].astype(np.float32)

        for i in range(1, len(images)):
            img = images[i].astype(np.float32)
            weight = weights[i]

            # Hard light is overlay with layers swapped
            mask = img < 128
            result_low = 2 * result * img / 255.0
            result_high = 255 - 2 * (255 - result) * (255 - img) / 255.0

            hard = np.where(mask, result_low, result_high)
            result = result * (1 - weight) + hard * weight

        return np.clip(result, 0, 255).astype(np.uint8)

    @staticmethod
    def maximum(images: List[np.ndarray], weights: np.ndarray) -> np.ndarray:
        """Maximum blend - takes brightest pixels"""
        # Weight-adjusted maximum
        result = np.zeros_like(images[0], dtype=np.float32)

        for img, weight in zip(images, weights):
            weighted_img = img.astype(np.float32) * weight
            result = np.maximum(result, weighted_img)

        # Normalize by sum of weights to maintain brightness
        result = result / np.sum(weights)

        return np.clip(result, 0, 255).astype(np.uint8)

    @staticmethod
    def minimum(images: List[np.ndarray], weights: np.ndarray) -> np.ndarray:
        """Minimum blend - takes darkest pixels"""
        # Weight-adjusted minimum
        result = np.ones_like(images[0], dtype=np.float32) * 255

        for img, weight in zip(images, weights):
            # Invert weight for minimum (higher weight = more influence on darkness)
            weighted_img = img.astype(np.float32) + (255 - img.astype(np.float32)) * (1 - weight)
            result = np.minimum(result, weighted_img)

        return np.clip(result, 0, 255).astype(np.uint8)

    @staticmethod
    def difference(images: List[np.ndarray], weights: np.ndarray) -> np.ndarray:
        """Difference blend - shows variations between scales"""
        if len(images) < 2:
            return images[0]

        result = np.zeros_like(images[0], dtype=np.float32)
        base = images[0].astype(np.float32)

        for i in range(1, len(images)):
            diff = np.abs(images[i].astype(np.float32) - base)
            result += diff * weights[i]

        # Normalize and enhance
        result = result / np.sum(weights[1:]) if np.sum(weights[1:]) > 0 else result

        return np.clip(result, 0, 255).astype(np.uint8)

    @staticmethod
    def grain_extract(images: List[np.ndarray], weights: np.ndarray) -> np.ndarray:
        """Grain extract - extracts detail differences"""
        if len(images) < 2:
            return images[0]

        result = np.ones_like(images[0], dtype=np.float32) * 128

        for i in range(1, len(images)):
            # Grain extract: result - image + 128
            grain = images[0].astype(np.float32) - images[i].astype(np.float32) + 128
            result = result * (1 - weights[i]) + grain * weights[i]

        return np.clip(result, 0, 255).astype(np.uint8)

    @staticmethod
    def grain_merge(images: List[np.ndarray], weights: np.ndarray) -> np.ndarray:
        """Grain merge - merges detail differences"""
        if len(images) < 2:
            return images[0]

        result = images[0].astype(np.float32)

        for i in range(1, len(images)):
            # Grain merge: result + image - 128
            grain = result + images[i].astype(np.float32) - 128
            result = result * (1 - weights[i]) + grain * weights[i]

        return np.clip(result, 0, 255).astype(np.uint8)

    @staticmethod
    def harmonic_mean(images: List[np.ndarray], weights: np.ndarray) -> np.ndarray:
        """Harmonic mean blend - emphasizes darker tones"""
        # Weighted harmonic mean
        epsilon = 1e-6
        result = np.zeros_like(images[0], dtype=np.float32)

        for img, weight in zip(images, weights):
            result += weight / (img.astype(np.float32) + epsilon)

        result = np.sum(weights) / (result + epsilon)

        return np.clip(result, 0, 255).astype(np.uint8)

    @staticmethod
    def geometric_mean(images: List[np.ndarray], weights: np.ndarray) -> np.ndarray:
        """Geometric mean blend - balanced non-linear mixing"""
        # Weighted geometric mean using log space
        result = np.zeros_like(images[0], dtype=np.float32)

        for img, weight in zip(images, weights):
            # Work in log space to handle the weighted product
            log_img = np.log(img.astype(np.float32) + 1)  # +1 to avoid log(0)
            result += log_img * weight

        result = np.exp(result) - 1

        return np.clip(result, 0, 255).astype(np.uint8)


